from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras
import os
import re

app = Flask(__name__)

DB_CONFIG = {
    "host": os.getenv("DB_HOST", "localhost"),
    "port": os.getenv("DB_PORT", "5432"),
    "dbname": os.getenv("DB_NAME", "postgres"),
    "user": os.getenv("DB_USER", "postgres"),
    "password": os.getenv("DB_PASSWORD", "postgres"),
}

IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

ALLOWED_OPERATORS = {
    "=": "=",
    "!=": "!=",
    "<>": "<>",
    "<": "<",
    "<=": "<=",
    ">": ">",
    ">=": ">=",
    "like": "LIKE",
    "ilike": "ILIKE",
    "in": "IN",
    "not in": "NOT IN",
    "is": "IS",
    "is not": "IS NOT",
}

ALLOWED_ORDER_DIRECTIONS = {"asc": "ASC", "desc": "DESC"}


def get_connection():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(name):
    if not isinstance(name, str) or not IDENTIFIER_RE.match(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def validate_table_name(table_name):
    if not isinstance(table_name, str):
        raise ValueError("table_name must be a string")
    parts = table_name.split(".")
    if len(parts) not in (1, 2):
        raise ValueError("table_name must be either table or schema.table")
    validated = [validate_identifier(part) for part in parts]
    return ".".join(validated)


def validate_columns(columns):
    if columns is None:
        return []
    if not isinstance(columns, list):
        raise ValueError("columns must be a list")
    return [validate_identifier(col) for col in columns]


def validate_limit_offset(value, field_name, default=None, max_value=10000):
    if value is None:
        return default
    if not isinstance(value, int):
        raise ValueError(f"{field_name} must be an integer")
    if value < 0 or value > max_value:
        raise ValueError(f"{field_name} must be between 0 and {max_value}")
    return value


def build_where_clause(filters, params):
    if not filters:
        return "", params

    if not isinstance(filters, list):
        raise ValueError("filters must be a list")

    clauses = []
    for f in filters:
        if not isinstance(f, dict):
            raise ValueError("Each filter must be an object")

        column = validate_identifier(f.get("column"))
        operator_raw = f.get("operator")
        if not isinstance(operator_raw, str):
            raise ValueError("operator must be a string")
        operator_key = operator_raw.strip().lower()
        if operator_key not in ALLOWED_OPERATORS:
            raise ValueError(f"Unsupported operator: {operator_raw}")
        operator = ALLOWED_OPERATORS[operator_key]
        value = f.get("value")

        if operator_key in {"in", "not in"}:
            if not isinstance(value, list) or len(value) == 0:
                raise ValueError(f"{operator_raw} requires a non-empty list value")
            placeholders = []
            for item in value:
                params.append(item)
                placeholders.append(f"%s")
            clauses.append(f"{column} {operator} ({', '.join(placeholders)})")
        elif operator_key in {"is", "is not"}:
            if value is not None and str(value).lower() not in {"null", "true", "false"}:
                raise ValueError(f"{operator_raw} only supports null/true/false")
            if value is None or str(value).lower() == "null":
                clauses.append(f"{column} {operator} NULL")
            elif str(value).lower() == "true":
                clauses.append(f"{column} {operator} TRUE")
            else:
                clauses.append(f"{column} {operator} FALSE")
        else:
            params.append(value)
            clauses.append(f"{column} {operator} %s")

    return " WHERE " + " AND ".join(clauses), params


def build_order_by(order_by):
    if not order_by:
        return ""
    if not isinstance(order_by, list):
        raise ValueError("order_by must be a list")

    parts = []
    for item in order_by:
        if not isinstance(item, dict):
            raise ValueError("Each order_by item must be an object")
        column = validate_identifier(item.get("column"))
        direction_raw = item.get("direction", "asc")
        if not isinstance(direction_raw, str):
            raise ValueError("direction must be a string")
        direction_key = direction_raw.strip().lower()
        if direction_key not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Unsupported order direction: {direction_raw}")
        parts.append(f"{column} {ALLOWED_ORDER_DIRECTIONS[direction_key]}")

    return " ORDER BY " + ", ".join(parts)


@app.route("/query", methods=["POST"])
def dynamic_query():
    try:
        payload = request.get_json(force=True, silent=False)
        if not isinstance(payload, dict):
            return jsonify({"error": "JSON body must be an object"}), 400

        table_name = validate_table_name(payload.get("table"))
        columns = validate_columns(payload.get("columns"))
        filters = payload.get("filters", [])
        order_by = payload.get("order_by", [])
        limit = validate_limit_offset(payload.get("limit"), "limit", default=100, max_value=10000)
        offset = validate_limit_offset(payload.get("offset"), "offset", default=0, max_value=1000000)

        select_clause = "*"
        if columns:
            select_clause = ", ".join(columns)

        params = []
        where_clause, params = build_where_clause(filters, params)
        order_clause = build_order_by(order_by)

        sql = f"SELECT {select_clause} FROM {table_name}{where_clause}{order_clause} LIMIT %s OFFSET %s"
        params.extend([limit, offset])

        with get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(sql, params)
                rows = cur.fetchall()

        return jsonify({
            "data": rows,
            "count": len(rows),
            "sql": sql,
        }), 200

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": "Database error", "details": str(e)}), 500
    except Exception as e:
        return jsonify({"error": "Internal server error", "details": str(e)}), 500


@app.route("/health", methods=["GET"])
def health():
    try:
        with get_connection() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
                cur.fetchone()
        return jsonify({"status": "ok"}), 200
    except Exception as e:
        return jsonify({"status": "error", "details": str(e)}), 500


